/**
 * Config Loader — HelloCash Business → Odoo accounting sync.
 * Validates env; returns config for $('Config Loader').first().json.
 * ODOO_API_KEY is required here but never included in output json.
 */

const NODE = 'Config Loader';

const REQUIRED = [
  'HELLOCASH_BASE_URL',
  'ODOO_BASE_URL',
  'ODOO_DB',
  'ODOO_UID',
  'ODOO_API_KEY',
  'ODOO_JOURNAL_ID',
  'ACCOUNT_KASSE',
  'ACCOUNT_BANK',
  'ACCOUNT_ERLOESE',
  'ACCOUNT_GUTSCHEIN',
  'ACCOUNT_UST_19',
  'SYNC_HOUR',
  'ERROR_EMAIL',
];

for (const name of REQUIRED) {
  const val = $env[name];
  if (val === undefined || val === null || String(val).trim() === '') {
    throw new Error(
      `${NODE}: required environment variable is missing or empty: ${name}. ` +
        'Set it in n8n (Settings → Variables / environment) and ensure this execution can read it.',
    );
  }
}

/** @param {string} label @param {string} urlRaw */
function validateBaseUrl(label, urlRaw) {
  const raw = String(urlRaw ?? '').trim();
  const normalized = raw.replace(/\/+$/, '');

  if (/^\d{2,5}$/.test(normalized)) {
    throw new Error(
      `${NODE}: ${label} must be a full URL, not just a port (got ${JSON.stringify(raw)}). ` +
        `Example: https://api.hellocash.com or http://host.docker.internal:8069`,
    );
  }

  const forSchemeCheck = normalized.replace(/\/jsonrpc\/?$/i, '');
  if (!/^https?:\/\//i.test(forSchemeCheck) && !forSchemeCheck.startsWith('//')) {
    throw new Error(
      `${NODE}: ${label} must start with http:// or https:// (current value: ${JSON.stringify(raw)}). ` +
        `Example (Docker → host): http://host.docker.internal:8069`,
    );
  }

  const candidate = forSchemeCheck.startsWith('//') ? `https:${forSchemeCheck}` : forSchemeCheck;
  const m = candidate.match(/^https?:\/\/([^\/?#]+)(\/|$)/i);
  const host = m ? m[1] : '';
  if (!host) {
    throw new Error(`${NODE}: ${label} is not a valid URL (got ${JSON.stringify(raw)}). Missing hostname.`);
  }

  return normalized;
}

validateBaseUrl('HELLOCASH_BASE_URL', String($env.HELLOCASH_BASE_URL));

const odooBaseRaw = String($env.ODOO_BASE_URL).trim();
const odooBaseForSchemeCheck = odooBaseRaw.replace(/\/jsonrpc\/?$/i, '').replace(/\/+$/, '');
if (!/^https?:\/\//i.test(odooBaseForSchemeCheck)) {
  throw new Error(
    `${NODE}: ODOO_BASE_URL must be a full URL starting with http:// or https:// (current value: ${JSON.stringify(odooBaseRaw)}). ` +
      'A port alone (e.g. 8069) is invalid. Example when n8n runs in Docker and Odoo is on the host: http://host.docker.internal:8069. ' +
      'If you use docker-compose, set ODOO_BASE_URL in a .env file next to docker-compose.yml (or pass --env-file), not only a bare port.',
  );
}

/** @param {string} envName @param {string | number} raw */
function parseIntEnv(envName, raw) {
  const n = parseInt(String(raw).trim(), 10);
  if (!Number.isFinite(n)) {
    throw new Error(
      `${NODE}: ${envName} must be a finite integer, got: ${JSON.stringify(raw)}. ` +
        `Example: ${envName}="123"`,
    );
  }
  return n;
}

/** Optional account id: empty env → fallbackInt (e.g. ACCOUNT_BANK). */
function parseIntEnvOrFallback(envName, fallbackInt) {
  const raw = $env[envName];
  if (raw === undefined || raw === null || String(raw).trim() === '') return fallbackInt;
  return parseIntEnv(envName, raw);
}

/** Optional Odoo journal id (empty env → null; mapping node falls back to ODOO_JOURNAL_ID). */
function parseJournalIdOptional(envName) {
  const raw = $env[envName];
  if (raw === undefined || raw === null || String(raw).trim() === '') return null;
  return parseIntEnv(envName, raw);
}

/** Optional env: integer ≥ min; ignores empty/missing env. */
function optionalIntGe(envName, defaultVal, min) {
  const raw = $env[envName];
  if (raw === undefined || raw === null || String(raw).trim() === '') return defaultVal;
  const n = parseInt(String(raw).trim(), 10);
  if (!Number.isFinite(n) || n < min) return defaultVal;
  return n;
}

const kasse = parseIntEnv('ACCOUNT_KASSE', $env.ACCOUNT_KASSE);
const bank = parseIntEnv('ACCOUNT_BANK', $env.ACCOUNT_BANK);
const erloese = parseIntEnv('ACCOUNT_ERLOESE', $env.ACCOUNT_ERLOESE);
const gutschein = parseIntEnv('ACCOUNT_GUTSCHEIN', $env.ACCOUNT_GUTSCHEIN);
const ust19 = parseIntEnv('ACCOUNT_UST_19', $env.ACCOUNT_UST_19);
const ust7 = parseIntEnvOrFallback('ACCOUNT_UST_7', ust19);
const accountEc = parseIntEnvOrFallback('ACCOUNT_EC', bank);
const accountKreditkarte = parseIntEnvOrFallback('ACCOUNT_KREDITKARTE', bank);
const accountRechnung = parseIntEnvOrFallback('ACCOUNT_RECHNUNG', bank);

const journalDefault = parseIntEnv('ODOO_JOURNAL_ID', $env.ODOO_JOURNAL_ID);
const journalKasse = parseJournalIdOptional('JOURNAL_KASSE');
const journalBank = parseJournalIdOptional('JOURNAL_BANK');
const journalVerkauf = parseJournalIdOptional('JOURNAL_VERKAUF');

/** @type {Record<string, unknown>} */
const config = {
  hellocash: {
    baseUrl: String($env.HELLOCASH_BASE_URL).trim().replace(/\/+$/, ''),
    timeoutMs: 30000,
  },

  odoo: {
    baseUrl: (() => {
      let u = String($env.ODOO_BASE_URL).trim().replace(/\/+$/, '');
      if (u.endsWith('/jsonrpc')) u = u.replace(/\/jsonrpc$/, '');
      return u;
    })(),
    db: String($env.ODOO_DB).trim(),
    uid: parseIntEnv('ODOO_UID', $env.ODOO_UID),
    journalId: journalDefault,
    /** Type-specific journals; null when unset — Map to Odoo falls back to journalId. */
    journalKasse,
    journalBank,
    journalVerkauf,
  },

  /** Odoo account.account ids for HelloCash payment routing (legacy + new). */
  accounts: {
    kasse,
    bank,
    erloese,
    gutschein,
    ec: accountEc,
    kreditkarte: accountKreditkarte,
    rechnung: accountRechnung,
    ust19,
    ust7,
  },

  /**
   * Legacy bucket map (withdrawals / tooling). Revenue posting routes by invoice_payment in Map to Odoo.
   */
  accountMap: {
    CASH: { debit: kasse, credit: erloese },
    EC: { debit: accountEc, credit: erloese },
    CREDITCARD: { debit: accountKreditkarte, credit: erloese },
    VOUCHER: { debit: gutschein, credit: erloese },
  },

  retry: {
    maxAttempts: optionalIntGe('SYNC_RPC_MAX_ATTEMPTS', 2, 1),
    intervalMs: optionalIntGe('SYNC_RPC_RETRY_INTERVAL_MS', 2500, 250),
  },

  syncHour: parseIntEnv('SYNC_HOUR', $env.SYNC_HOUR),

  errorEmail: String($env.ERROR_EMAIL).trim(),

  /** Flat copies for operators / downstream (same values as accounts.* / odoo.journal*). */
  ACCOUNT_EC: accountEc,
  ACCOUNT_KREDITKARTE: accountKreditkarte,
  ACCOUNT_RECHNUNG: accountRechnung,
  ACCOUNT_UST_19: ust19,
  ACCOUNT_UST_7: ust7,
  JOURNAL_KASSE: journalKasse,
  JOURNAL_BANK: journalBank,
  JOURNAL_VERKAUF: journalVerkauf,
};

return [{ json: config }];

/**
 * HelloCash Business — bulk fetch (production).
 * Primary: GET `/api/v1/invoices` (invoice documents with `taxes[]` / rates when the API provides them), paginated with limit/offset and optional dateFrom/dateTo.
 * Response rows are `.invoices` and/or `.entries` (same extraction for both). Skips cancelled rows. Output: hellocashData.entries + hellocashData.invoices index by invoice number.
 *
 * Kassenbuch (`/api/v1/cashBook`) does not carry VAT breakdown; this node does not use it as the primary source so tax-aware posting matches the invoices API.
 *
 * Env: HELLOCASH_API_TOKEN (required). Paths are fixed in this node (not env).
 * HELLOCASH_BASE_URL may be origin-only or include /api/v1 — overlapping path segments are merged.
 * HELLOCASH_QUERY_FROM / HELLOCASH_QUERY_TO → dateFrom & dateTo.
 * Pagination: HELLOCASH_CASHBOOK_LIMIT / HELLOCASH_CASHBOOK_OFFSET / HELLOCASH_CASHBOOK_MAX_PAGES (legacy names; same as invoice list).
 * Optional: HELLOCASH_IGNORE_SYNC_HOUR=1, SYNC_HOUR gate via Config.
 */

const NODE = 'HelloCash Fetch';

/**
 * Only include query keys that are actually set (not null/undefined; strings non-empty after trim).
 * @param {unknown} v
 */
function queryParamHasValue(v) {
  if (v === null || v === undefined) return false;
  if (typeof v === 'string') return v.trim() !== '';
  return true;
}

/** @param {Record<string, string | number | boolean>} params */
function buildQueryString(params) {
  return Object.keys(params)
    .filter((k) => queryParamHasValue(params[k]))
    .map((k) => `${encodeURIComponent(k)}=${encodeURIComponent(String(params[k]))}`)
    .join('&');
}

/**
 * Merge HELLOCASH_BASE_URL with an absolute path without duplicating shared segments.
 * e.g. base https://host/api/v1 + path /api/v1/invoices → https://host/api/v1/invoices
 * Protocol-relative bases (//host/...) are normalized to https://host/...
 *
 * @param {string} baseUrlRaw
 * @param {string} pathRaw absolute path, e.g. /api/v1/invoices
 */
function joinBaseUrlAndPath(baseUrlRaw, pathRaw) {
  let baseStr = String(baseUrlRaw || '').trim();
  if (baseStr.startsWith('//')) baseStr = `https:${baseStr}`;
  baseStr = baseStr.replace(/\/+$/, '');

  const relPath = pathRaw.startsWith('/') ? pathRaw : `/${pathRaw}`;

  // n8n Code nodes run in a sandbox where global URL may be undefined.
  // Parse scheme/host/path conservatively using regex.
  const m = baseStr.match(/^(https?:\/\/[^\/?#]+)(\/[^?#]*)?$/i);
  if (!m) {
    return `${baseStr}${relPath}`;
  }
  const origin = m[1];
  const basePath = String(m[2] || '').replace(/\/+$/, '');
  const baseSegs = basePath.split('/').filter(Boolean);
  const pathSegs = relPath.split('/').filter(Boolean);

  let overlap = 0;
  const max = Math.min(baseSegs.length, pathSegs.length);
  for (let k = max; k >= 1; k--) {
    let ok = true;
    for (let i = 0; i < k; i++) {
      if (baseSegs[baseSegs.length - k + i] !== pathSegs[i]) {
        ok = false;
        break;
      }
    }
    if (ok) {
      overlap = k;
      break;
    }
  }

  const remainder = pathSegs.slice(overlap);
  const mergedSegs = [...baseSegs, ...remainder];
  return `${origin}/${mergedSegs.join('/')}`.replace(/\/+$/, '');
}

/**
 * n8n httpRequest: omit null/undefined options (some versions reject explicit nulls).
 * @param {Record<string, unknown>} opts
 */
function httpRequestOpts(opts) {
  /** @type {Record<string, unknown>} */
  const out = {};
  for (const [k, v] of Object.entries(opts)) {
    if (v !== null && v !== undefined) out[k] = v;
  }
  return out;
}

/**
 * Drop null/undefined and empty strings from nested objects for logs (avoid "parameters" with no value).
 * @param {unknown} value
 */
function compactForDisplay(value) {
  if (value === null || value === undefined) return undefined;
  if (Array.isArray(value)) {
    const arr = value.map(compactForDisplay).filter((x) => x !== undefined);
    return arr.length ? arr : undefined;
  }
  if (typeof value === 'object') {
    const o = {};
    for (const [k, v] of Object.entries(value)) {
      const c = compactForDisplay(v);
      if (c !== undefined) o[k] = c;
    }
    return Object.keys(o).length ? o : undefined;
  }
  if (typeof value === 'string' && value.trim() === '') return undefined;
  return value;
}

/**
 * One or two sentences an operator can act on (not only raw status/body).
 * @param {string|number} status
 * @param {{ name?: string, code?: string, httpCode?: string, message?: string, description?: string }} hint
 * @param {string} bodyStr
 */
function deriveFailureExplanation(status, hint, bodyStr) {
  const code = String(hint?.code ?? '');
  const msg = String(hint?.message ?? hint?.description ?? '');
  const statusNum = typeof status === 'number' ? status : parseInt(String(status), 10);
  const body = String(bodyStr ?? '');
  const combined = `${msg} ${code} ${body}`.toLowerCase();

  const parts = [];

  if (Number.isFinite(statusNum)) {
    if (statusNum === 401 || statusNum === 403) {
      parts.push(
        'The API rejected authentication/authorization — verify HELLOCASH_API_TOKEN and that HELLOCASH_BASE_URL matches the environment where that token is valid.',
      );
    } else if (statusNum === 404) {
      parts.push(
        'The server returned 404 — check HELLOCASH_BASE_URL (HelloCash paths are /api/v1/cashBook and /api/v1/invoices).',
      );
    } else if (statusNum === 400 || statusNum === 422) {
      parts.push(
        'The server rejected the request parameters — review date/search/limit/offset env vars against the API contract.',
      );
    } else if (statusNum === 429) {
      parts.push('Rate limited (429) — retry later or reduce call volume.');
    } else if (statusNum >= 500 && statusNum < 600) {
      parts.push(
        `Server error (${statusNum}) — HelloCash may be unavailable; retry later or check their service status.`,
      );
    } else if (statusNum >= 200 && statusNum < 300) {
      parts.push(
        'HTTP status looks successful but the client still failed — the body may not be JSON while json:true is set, or the client threw for another reason.',
      );
    }
  }

  if (status === 'no-status' || !Number.isFinite(statusNum)) {
    if (/enotfound|getaddrinfo|eai_again/i.test(combined) || code === 'ENOTFOUND') {
      parts.push('DNS or hostname resolution failed — check HELLOCASH_BASE_URL and network/DNS.');
    }
    if (/econnrefused/i.test(combined) || code === 'ECONNREFUSED') {
      parts.push('Connection refused — wrong host/port, service not listening, or firewall.');
    }
    if (/etimedout|esockettimedout|timeout/i.test(combined) || /timeout/i.test(code)) {
      parts.push('Request timed out — increase HelloCash timeout in config, or check network/API availability.');
    }
    if (/cert|ssl|tls|unable_to_verify/i.test(combined)) {
      parts.push('TLS/certificate error — check HTTPS URL, proxy, or corporate TLS inspection.');
    }
  }

  if (/unexpected token|not valid json|invalid json|json parse/i.test(combined)) {
    parts.push('Response was not valid JSON — wrong URL often returns HTML or an error page instead of the API.');
  }
  if (/<!doctype html|<html/i.test(body)) {
    parts.push('Body looks like HTML — usually wrong API URL, redirect to a web login, or a gateway error page.');
  }

  if (parts.length === 0) {
    parts.push(
      'Could not infer a specific cause from status/body — use HTTP status, hint fields, and response snippet below.',
    );
  }

  return parts.join(' ');
}

/**
 * Best-effort HTTP status from n8n httpRequest / axios / nested cause chain.
 * @param {unknown} e
 */
function resolveHttpStatus(e) {
  /** @param {unknown} x */
  const asStatus = (x) => {
    if (x === undefined || x === null || x === '') return undefined;
    if (typeof x === 'number' && Number.isFinite(x)) return x;
    const n = parseInt(String(x), 10);
    if (Number.isFinite(n)) return n;
    if (typeof x === 'string') return x.trim() || undefined;
    return undefined;
  };

  let cur = e;
  for (let d = 0; d < 6 && cur != null; d++) {
    if (typeof cur !== 'object') break;
    const o = /** @type {Record<string, unknown>} */ (cur);
    const u =
      asStatus(o.response?.status) ??
      asStatus(o.response?.statusCode) ??
      asStatus(
        o.error && typeof o.error === 'object'
          ? /** @type {{ status?: unknown, statusCode?: unknown }} */ (o.error).status ??
              /** @type {{ status?: unknown, statusCode?: unknown }} */ (o.error).statusCode ??
              undefined
          : undefined,
      ) ??
      asStatus(o.httpCode) ??
      asStatus(o.statusCode) ??
      asStatus(o.status);
    if (u !== undefined) return u;
    cur = o.cause;
  }

  const msg = String(
    (typeof e === 'object' && e && 'message' in e && /** @type {{ message: unknown }} */ (e).message) || '',
  );
  const m =
    msg.match(/\bstatus code\s+(\d{3})\b/i) ??
    msg.match(/\bHTTP\s+(\d{3})\b/) ??
    msg.match(/^\s*(\d{3})\s/);
  if (m) return parseInt(m[1], 10);

  return 'no-status';
}

/**
 * n8n httpRequest errors are often NodeApiError / wrapped request errors — not always axios-shaped (e.response).
 */
function extractHttpFailureDetails(e) {
  const status = resolveHttpStatus(e);

  let body =
    e?.response?.data ??
    e?.response?.body ??
    e?.error ??
    e?.description ??
    (Array.isArray(e?.messages) ? e.messages.join('; ') : e?.messages);

  if ((body === undefined || body === null || body === '') && e?.cause) {
    const c = e.cause;
    body =
      c?.response?.data ??
      c?.response?.body ??
      c?.message ??
      (typeof c === 'string' ? c : undefined);
  }

  let bodyStr = 'no body';
  if (body !== undefined && body !== null && body !== '') {
    bodyStr = typeof body === 'string' ? body : JSON.stringify(body, null, 2);
  }

  const hint = {
    name: e?.name,
    code: e?.code,
    httpCode: e?.httpCode,
    description: e?.description,
    message: e?.message,
    stack: typeof e?.stack === 'string' ? e.stack : undefined,
    errorKeys: e && typeof e === 'object' ? Object.keys(e) : [],
  };

  /** @param {unknown} err @param {number} depth */
  function shallowDump(err, depth) {
    if (err == null) return null;
    if (typeof err !== 'object') return String(err);
    const o = {};
    try {
      for (const k of Object.getOwnPropertyNames(err)) {
        try {
          let v = /** @type {object} */ (err)[k];
          if (v && typeof v === 'object' && depth < 2) {
            v = shallowDump(v, depth + 1);
          }
          if (typeof v === 'string' && v.length > 4000) v = v.slice(0, 4000) + '…';
          o[k] = v;
        } catch {
          o[k] = '[unreadable]';
        }
      }
    } catch {
      return '[dump failed]';
    }
    return o;
  }

  const rawDump = shallowDump(e, 0);
  let causeChain = [];
  let c = e?.cause;
  let depth = 0;
  while (c != null && depth < 5) {
    causeChain.push({
      depth,
      message: c?.message ?? String(c),
      name: c?.name,
      stack: typeof c?.stack === 'string' ? c.stack.slice(0, 2000) : undefined,
    });
    c = c?.cause;
    depth++;
  }

  return { status, bodyStr, hint, rawDump, causeChain };
}

/** Mask secret for logs (never log full token). */
function maskToken(t) {
  const s = String(t || '');
  if (!s) return '(empty)';
  if (s.length <= 8) return `${s.slice(0, 2)}…(${s.length} chars)`;
  return `${s.slice(0, 4)}…${s.slice(-2)} (len=${s.length})`;
}

function safeJson(obj, space) {
  try {
    return JSON.stringify(obj, null, space);
  } catch {
    return '[JSON.stringify failed — possibly circular]';
  }
}

function nowIso() {
  return new Date().toISOString();
}

/**
 * Exponential backoff with jitter.
 * @param {number} attempt 1..n
 * @param {number} baseMs
 * @param {number} maxMs
 */
function backoffDelayMs(attempt, baseMs, maxMs) {
  const exp = Math.min(maxMs, baseMs * Math.pow(2, Math.max(0, attempt - 1)));
  const jitter = Math.floor(Math.random() * Math.min(250, exp * 0.1));
  return exp + jitter;
}

/**
 * Simple circuit breaker: after N consecutive failures, stop for cooldownMs.
 */
function createCircuitBreaker({ failureThreshold, cooldownMs }) {
  let consecutive = 0;
  let openUntil = 0;
  return {
    /** @param {string} op */
    assertClosed(op) {
      const now = Date.now();
      if (openUntil && now < openUntil) {
        const remainingMs = openUntil - now;
        throw new Error(
          `${NODE}: circuit breaker OPEN for ${op} (cooldown ${Math.ceil(remainingMs / 1000)}s remaining). ` +
            `Too many consecutive failures; check HelloCash availability and configuration before retrying.`,
        );
      }
    },
    success() {
      consecutive = 0;
      openUntil = 0;
    },
    failure() {
      consecutive++;
      if (consecutive >= failureThreshold) {
        openUntil = Date.now() + cooldownMs;
      }
    },
  };
}

const config = $('Config Loader').first().json;
const token = $env.HELLOCASH_API_TOKEN?.trim();
if (!token) {
  throw new Error(
    `${NODE}: HELLOCASH_API_TOKEN missing. Example: HELLOCASH_API_TOKEN="eyJhbGciOi..." (do not paste into logs).`,
  );
}

const ignoreHour =
  $env.HELLOCASH_IGNORE_SYNC_HOUR === '1' ||
  String($env.HELLOCASH_IGNORE_SYNC_HOUR || '').toLowerCase() === 'true';
const hour = new Date().getHours();
const syncHour = parseInt(String(config.syncHour), 10);
if (!Number.isFinite(syncHour)) {
  throw new Error(`${NODE}: config.syncHour is invalid (expected integer), got: ${JSON.stringify(config.syncHour)}`);
}
if (!ignoreHour && hour !== syncHour) {
  return [
    {
      json: {
        skipped: true,
        reason: 'sync_hour',
        syncHour,
        currentHour: hour,
      },
    },
  ];
}

let baseUrl = String(config.hellocash.baseUrl || '')
  .trim()
  .replace(/\/+$/, '');
if (baseUrl.startsWith('//')) baseUrl = `https:${baseUrl}`;

/** HelloCash Business API paths (fixed; join with HELLOCASH_BASE_URL). */
const HELLOCASH_PATH_CASHBOOK = '/api/v1/cashBook';
const HELLOCASH_PATH_INVOICES = '/api/v1/invoices';

const daysBack = parseInt(String($env.HELLOCASH_DAYS_BACK || '1'), 10);

function toDateString(d) {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
}
const today = new Date();
const fromDate = new Date(today);
fromDate.setDate(today.getDate() - daysBack);

const qFromRaw = $env.HELLOCASH_QUERY_FROM && String($env.HELLOCASH_QUERY_FROM).trim();
const qFrom = qFromRaw ? qFromRaw : toDateString(fromDate);

const qToRaw = $env.HELLOCASH_QUERY_TO && String($env.HELLOCASH_QUERY_TO).trim();
const qTo = qToRaw ? qToRaw : toDateString(today);

const listOffsetRaw =
  $env.HELLOCASH_CASHBOOK_OFFSET !== undefined && $env.HELLOCASH_CASHBOOK_OFFSET !== null
    ? String($env.HELLOCASH_CASHBOOK_OFFSET)
    : $env.HELLOCASH_INVOICES_OFFSET !== undefined && $env.HELLOCASH_INVOICES_OFFSET !== null
      ? String($env.HELLOCASH_INVOICES_OFFSET)
      : '0';

const listUrlNoQuery = joinBaseUrlAndPath(baseUrl, HELLOCASH_PATH_INVOICES);

if (!String(baseUrl || '').trim()) {
  throw new Error(
    'HelloCash Fetch: config.hellocash.baseUrl is empty. Re-run Config Loader and set HELLOCASH_BASE_URL (non-empty).',
  );
}

const { maxAttempts, intervalMs } = config.retry;
/** @type {Record<string, string>} */
const authHeaders = {
  Authorization: `Bearer ${token}`,
  Accept: 'application/json',
};

/**
 * Invoice list from GET …/invoices: Apiary/docs use `invoices`; live responses may use `entries` for the same array.
 * @param {unknown} res
 */
function invoiceListFromResponse(res) {
  if (!res || typeof res !== 'object') return [];
  const o = /** @type {Record<string, unknown>} */ (res);
  if (Array.isArray(o.invoices)) return o.invoices;
  if (Array.isArray(o.entries)) return o.entries;
  const data = o.data;
  if (data && typeof data === 'object') {
    const d = /** @type {Record<string, unknown>} */ (data);
    if (Array.isArray(d.invoices)) return d.invoices;
    if (Array.isArray(d.entries)) return d.entries;
  }
  return [];
}

/** @param {unknown} inv */
function looksLikeCashBookRow(inv) {
  if (!inv || typeof inv !== 'object') return false;
  const o = /** @type {Record<string, unknown>} */ (inv);
  return 'cashBook_total' in o || 'cashBook_id' in o || 'cashBook_invoice_number' in o;
}

/** @param {unknown} inv */
function hasUsableTaxBreakdown(inv) {
  if (!inv || typeof inv !== 'object') return false;
  const o = /** @type {Record<string, unknown>} */ (inv);
  if (!Array.isArray(o.taxes) || o.taxes.length === 0) return false;
  for (const tx of o.taxes) {
    if (!tx || typeof tx !== 'object') continue;
    const t = /** @type {Record<string, unknown>} */ (tx);
    const net = t.tax_net;
    const tax = t.tax_tax;
    if (net !== null && net !== undefined && String(net).trim() !== '') return true;
    if (tax !== null && tax !== undefined && String(tax).trim() !== '') return true;
  }
  return false;
}

/** Stable key for hellocashData.invoices (number preferred, else id). */
function invoiceRecordKey(inv) {
  if (!inv || typeof inv !== 'object') return '';
  const o = /** @type {Record<string, unknown>} */ (inv);
  const num = String(
    o.invoice_number ??
      o.invoiceNumber ??
      o.number ??
      o.document_number ??
      o.documentNumber ??
      o.cashBook_invoice_number ??
      '',
  ).trim();
  if (num && num !== '0') return num;
  const id = String(
    o.invoice_id ?? o.invoiceId ?? o.invoice_uid ?? o.uid ?? o.cashBook_id ?? o.id ?? '',
  ).trim();
  return id;
}

/** @param {unknown} inv */
function skipCancelledListRow(inv) {
  if (!inv || typeof inv !== 'object') return true;
  const o = /** @type {Record<string, unknown>} */ (inv);
  if (o.invoice_cancellation === '1') return true;
  if (o.cashBook_cancellation === '1') return true;
  return false;
}

const breaker = createCircuitBreaker({
  failureThreshold: parseInt(String($env.HELLOCASH_CB_FAILURE_THRESHOLD || '4'), 10) || 4,
  cooldownMs: parseInt(String($env.HELLOCASH_CB_COOLDOWN_MS || '120000'), 10) || 120000,
});

/**
 * HTTP GET with retry/backoff and circuit breaker.
 * @param {{ url: string, timeoutMs: number, op: string }} p
 */
const getJsonWithRetry = async ({ url, timeoutMs, op }) => {
  let lastError = null;
  /** @type {object[]} */
  const attempts = [];
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    const startedAt = nowIso();
    try {
      breaker.assertClosed(op);
      const res = await this.helpers.httpRequest(
        httpRequestOpts({
          method: 'GET',
          url,
          headers: authHeaders,
          timeout: timeoutMs,
          json: true,
        }),
      );
      breaker.success();
      return { ok: true, res, attempts };
    } catch (e) {
      breaker.failure();
      const { status, bodyStr, hint, rawDump, causeChain } = extractHttpFailureDetails(e);
      const hintCompact = compactForDisplay(hint) ?? {};
      const failureExplanation = deriveFailureExplanation(status, hint, bodyStr);
      attempts.push({
        attempt,
        of: maxAttempts,
        at: startedAt,
        op,
        httpStatus: status,
        failureExplanation,
        url,
        request: {
          method: 'GET',
          timeoutMs,
          accept: authHeaders.Accept,
          authorization: `Bearer ${maskToken(token)}`,
        },
        responseBody: bodyStr,
        hint: hintCompact,
        rawDump,
        causeChain,
      });
      lastError = e;
      console.error(`${NODE}: ${op} failed — attempt detail`, attempts[attempts.length - 1]);
      if (attempt < maxAttempts) {
        const delay = backoffDelayMs(attempt, intervalMs, 30000);
        await new Promise((r) => setTimeout(r, delay));
      }
    }
  }
  return { ok: false, res: null, attempts, lastError };
};

let lastErr;
/** @type {unknown} */
let listResponse;
/** @type {object[]} */
const listAttemptHistory = [];

const listLimit = Math.max(1, parseInt(String($env.HELLOCASH_CASHBOOK_LIMIT || $env.HELLOCASH_INVOICES_LIMIT || '1000'), 10) || 1000);
const listOffsetStart = Math.max(0, parseInt(String(listOffsetRaw || '0'), 10) || 0);
const maxListPages = Math.max(
  1,
  parseInt(String($env.HELLOCASH_CASHBOOK_MAX_PAGES || $env.HELLOCASH_INVOICES_MAX_PAGES || '50'), 10) || 50,
);

/** @type {object[]} */
const allInvoices = [];
let pageOffset = listOffsetStart;
for (let page = 1; page <= maxListPages; page++) {
  const pageQuery = buildQueryString({
    limit: String(listLimit),
    offset: String(pageOffset),
    dateFrom: qFrom,
    dateTo: qTo,
  });
  const pageUrl = pageQuery ? `${listUrlNoQuery}?${pageQuery}` : listUrlNoQuery;

  const { ok, res, attempts, lastError } = await getJsonWithRetry({
    url: pageUrl,
    timeoutMs: config.hellocash.timeoutMs,
    op: `invoices GET page=${page} offset=${pageOffset} limit=${listLimit}`,
  });
  listAttemptHistory.push(...attempts);
  if (!ok) {
    lastErr = lastError instanceof Error ? lastError : new Error(String(lastError || 'unknown error'));
    listResponse = undefined;
    break;
  }

  listResponse = res;
  const pageInvoices = invoiceListFromResponse(res);
  if (pageInvoices.length === 0) break;

  for (const inv of pageInvoices) {
    if (!inv || typeof inv !== 'object') continue;
    if (skipCancelledListRow(inv)) continue;
    allInvoices.push(inv);
  }

  if (pageInvoices.length < listLimit) break;
  pageOffset += listLimit;
}

if (listResponse === undefined) {
  const lastAtt =
    listAttemptHistory.length > 0 ? listAttemptHistory[listAttemptHistory.length - 1] : {};

  const lastHttp = lastAtt.httpStatus ?? lastAtt.status ?? 'no-status';

  const bodyOneLine = String(lastAtt.responseBody ?? '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 500);
  const hintMsg = lastAtt.hint?.message ?? lastAtt.hint?.description ?? 'n/a';
  const hintCode = lastAtt.hint?.code ?? lastAtt.hint?.httpCode ?? 'n/a';
  const failureExplanation =
    lastAtt.failureExplanation ?? deriveFailureExplanation(lastHttp, lastAtt.hint ?? {}, bodyOneLine);

  const diagnostic = {
    phase: 'invoices GET',
    httpStatus: lastHttp,
    nodeErrorCode: hintCode,
    failureExplanation,
    failedAfterAttempts: maxAttempts,
    retryIntervalMs: intervalMs,
    clock: { hour, syncHour: config.syncHour, ignoreSyncHour: ignoreHour },
    token: maskToken(token),
    listUrl: listUrlNoQuery,
    apiPaths: {
      cashBook: HELLOCASH_PATH_CASHBOOK,
      invoices: HELLOCASH_PATH_INVOICES,
    },
    attemptHistory: listAttemptHistory,
    lastErrorMessage: lastErr?.message ?? 'unknown',
    lastErrorStack: lastErr?.stack ?? 'no stack',
  };

  const diagnosticJson = safeJson(diagnostic, 2);

  console.error('HelloCash invoices — FINAL FAILURE (all attempts exhausted)', {
    httpStatus: lastHttp,
    nodeErrorCode: hintCode,
    ...diagnostic,
  });

  const explainOneLine = String(failureExplanation).replace(/\s+/g, ' ').trim().slice(0, 280);

  const httpStatusStr =
    lastHttp !== undefined && lastHttp !== null && lastHttp !== 'no-status'
      ? `HTTP ${lastHttp}`
      : 'HTTP status unknown (no response — network/DNS/TLS/wrong URL?)';

  const errorFirstLine =
    `${httpStatusStr} | nodeErrorCode=${hintCode} | HelloCash invoices GET failed | ${explainOneLine} | ${hintMsg} | URL=${listUrlNoQuery} | body=${bodyOneLine || '(empty)'}`;

  const msg =
    `${errorFirstLine}\n` +
    `\n` +
    `--- CONTEXT ---\n` +
    `httpStatus: ${lastHttp}  nodeErrorCode: ${hintCode}\n` +
    `listUrl: ${listUrlNoQuery}\n` +
    `timeoutMs: ${config.hellocash.timeoutMs}  retryIntervalMs: ${intervalMs}\n` +
    `token (masked): ${maskToken(token)}\n` +
    `syncHour: ${config.syncHour}  currentHour: ${hour}  ignoreSyncHour: ${ignoreHour}\n` +
    `--- DIAGNOSTIC JSON ---\n` +
    diagnosticJson;

  const err = new Error(msg);
  err.diagnostic = diagnostic;
  err.attemptHistory = listAttemptHistory;
  throw err;
}

const entries = allInvoices;
if (entries.length === 0) {
  return [{ json: { skipped: false, empty: true, message: 'No HelloCash entries (after filtering cancellations)' } }];
}

/** @type {Record<string, object>} */
const invoicesRecord = {};
for (const inv of entries) {
  if (!inv || typeof inv !== 'object') continue;
  if (looksLikeCashBookRow(inv) && !hasUsableTaxBreakdown(inv)) continue;
  const n = invoiceRecordKey(inv);
  if (n) invoicesRecord[n] = /** @type {object} */ (inv);
}

const entryShape =
  entries[0] && typeof entries[0] === 'object' && looksLikeCashBookRow(entries[0]) ? 'cashbook' : 'invoice';
const metaSource = entryShape === 'cashbook' ? 'cashbook' : 'invoices';

return [
  {
    json: {
      skipped: false,
      hellocashData: {
        entries,
        invoices: invoicesRecord,
        meta: {
          fetchedAt: nowIso(),
          entryCount: entries.length,
          invoiceCount: Object.keys(invoicesRecord).length,
          daysBack: Number.isFinite(daysBack) ? daysBack : 1,
          syncHour: syncHour,
          source: metaSource,
          entryShape,
          apiPaths: {
            cashBook: HELLOCASH_PATH_CASHBOOK,
            invoices: HELLOCASH_PATH_INVOICES,
          },
          invoiceEnrich: {
            enabled: false,
          },
        },
      },
    },
  },
];

/**
 * Map HelloCash invoice rows → Odoo account.move payloads.
 * Routes by invoice_payment (API: Bar, Bankomat, Kreditkarte, Kreditrechnung). All lines use tax_ids: [].
 */

const NODE = 'Map to Odoo';

const config = $('Config Loader').first().json;
const input = items[0].json;

if (input.skipped || input.empty) {
  return [{ json: input }];
}

const hc = input.hellocashData;
if (!hc?.entries) {
  return [{ json: { skipped: false, mappedEmpty: true, message: 'Missing hellocashData.entries' } }];
}

const { entries } = hc;

/**
 * @param {unknown} specific Journal id from env (may be null).
 * @param {Record<string, unknown>} odoo
 * @param {string} envName For error messages.
 */
function resolveJournal(specific, odoo, envName) {
  const def = odoo.journalId;
  if (specific !== null && specific !== undefined && Number.isFinite(specific) && parseInt(String(specific), 10) > 0) {
    return parseInt(String(specific), 10);
  }
  const d = def !== null && def !== undefined ? parseInt(String(def), 10) : NaN;
  if (Number.isFinite(d) && d > 0) return d;
  throw new Error(
    `${NODE}: journal resolution failed: set ${envName} or a valid ODOO_JOURNAL_ID (both missing or invalid).`,
  );
}

/**
 * HelloCash invoice_payment → internal route key.
 * @param {unknown} raw
 */
function normalizeInvoicePayment(raw) {
  const t = String(raw ?? '').trim();
  if (!t) return null;
  const lower = t.toLowerCase();
  if (lower === 'bar') return 'BAR';
  if (lower === 'bankomat') return 'BANKOMAT';
  if (lower === 'kreditkarte') return 'KREDITKARTE';
  if (lower === 'kreditrechnung') return 'KREDITRECHNUNG';
  return null;
}

/** @param {Record<string, unknown>} inv */
function isInvoiceCancelled(inv) {
  if (!inv || typeof inv !== 'object') return true;
  const ic = inv.invoice_cancellation;
  if (ic === true || ic === 1 || ic === '1') return true;
  const s = String(ic ?? '')
    .trim()
    .toLowerCase();
  if (s === 'true' || s === 'yes' || s === 'ja') return true;
  const cb = inv.cashBook_cancellation;
  if (cb === true || cb === 1 || cb === '1') return true;
  return false;
}

/**
 * Gross amount: prefer invoice_total; fall back to common API / legacy cashbook fields, EU decimals, then taxes[].tax_gross.
 * @param {Record<string, unknown>} row
 */
function parseInvoiceGross(row) {
  const keys = [
    'invoice_total',
    'invoice_gross_total',
    'invoice_amount',
    'invoice_sum',
    'gross_total',
    'cashBook_total',
  ];
  for (const k of keys) {
    const v = row[k];
    if (v === null || v === undefined) continue;
    if (typeof v === 'number' && Number.isFinite(v) && v !== 0) return Math.abs(v);
    const t = String(v).trim().replace(/\s/g, '');
    if (!t) continue;
    let n = NaN;
    if (/^\d{1,3}(\.\d{3})+,\d{1,4}$/.test(t)) {
      n = parseFloat(t.replace(/\./g, '').replace(',', '.'));
    } else if (/^\d+,\d+$/.test(t)) {
      n = parseFloat(t.replace(',', '.'));
    } else {
      n = parseFloat(t);
    }
    if (Number.isFinite(n) && n !== 0) return Math.abs(n);
  }
  if (Array.isArray(row.taxes)) {
    let sum = 0;
    for (const tx of row.taxes) {
      if (!tx || typeof tx !== 'object') continue;
      const g = /** @type {{ tax_gross?: unknown }} */ (tx).tax_gross;
      if (g === null || g === undefined) continue;
      const t = String(g).trim().replace(/\s/g, '').replace(',', '.');
      const n = parseFloat(t);
      if (Number.isFinite(n)) sum += n;
    }
    if (sum > 0) return Math.abs(sum);
  }
  return NaN;
}

/**
 * Net amount from HelloCash `taxes[]`: sum `tax_net` using the same per-cell parsing as `parseInvoiceGross` header fields.
 * @param {Record<string, unknown>} row
 */
function parseInvoiceNet(row) {
  if (!Array.isArray(row.taxes)) return NaN;
  let sum = 0;
  let any = false;
  for (const tx of row.taxes) {
    if (!tx || typeof tx !== 'object') continue;
    const v = /** @type {{ tax_net?: unknown }} */ (tx).tax_net;
    if (v === null || v === undefined) continue;
    if (typeof v === 'number' && Number.isFinite(v)) {
      sum += Math.abs(v);
      any = true;
      continue;
    }
    const t = String(v).trim().replace(/\s/g, '');
    if (!t) continue;
    let n = NaN;
    if (/^\d{1,3}(\.\d{3})+,\d{1,4}$/.test(t)) {
      n = parseFloat(t.replace(/\./g, '').replace(',', '.'));
    } else if (/^\d+,\d+$/.test(t)) {
      n = parseFloat(t.replace(',', '.'));
    } else {
      n = parseFloat(t);
    }
    if (Number.isFinite(n)) {
      sum += Math.abs(n);
      any = true;
    }
  }
  if (!any) return NaN;
  return Math.abs(sum);
}

/**
 * VAT from HelloCash `taxes[]`: sum `tax_tax` with the same parsing as net. If no `tax_tax` on any line, use |gross − net|.
 * @param {Record<string, unknown>} row
 */
function parseInvoiceVat(row) {
  const gross = parseInvoiceGross(row);
  const net = parseInvoiceNet(row);
  if (!Array.isArray(row.taxes)) {
    if (Number.isFinite(gross) && Number.isFinite(net)) return Math.abs(gross - net);
    return NaN;
  }
  let sum = 0;
  let any = false;
  for (const tx of row.taxes) {
    if (!tx || typeof tx !== 'object') continue;
    const v = /** @type {{ tax_tax?: unknown }} */ (tx).tax_tax;
    if (v === null || v === undefined) continue;
    if (typeof v === 'number' && Number.isFinite(v)) {
      sum += Math.abs(v);
      any = true;
      continue;
    }
    const t = String(v).trim().replace(/\s/g, '');
    if (!t) continue;
    let n = NaN;
    if (/^\d{1,3}(\.\d{3})+,\d{1,4}$/.test(t)) {
      n = parseFloat(t.replace(/\./g, '').replace(',', '.'));
    } else if (/^\d+,\d+$/.test(t)) {
      n = parseFloat(t.replace(',', '.'));
    } else {
      n = parseFloat(t);
    }
    if (Number.isFinite(n)) {
      sum += Math.abs(n);
      any = true;
    }
  }
  if (any) return Math.abs(sum);
  if (Number.isFinite(gross) && Number.isFinite(net)) return Math.abs(gross - net);
  return NaN;
}

/** @param {Record<string, unknown>} row @param {string[]} keys */
function pickFirstString(row, keys) {
  for (const k of keys) {
    if (!(k in row)) continue;
    const v = row[k];
    if (v === null || v === undefined) continue;
    const s = String(v).trim();
    if (s) return s;
  }
  return '';
}

/** @param {Record<string, unknown>} row */
function invoiceNumberFrom(row) {
  return pickFirstString(row, [
    'invoice_number',
    'invoiceNumber',
    'invoice_nr',
    'invoiceNr',
    'number',
    'document_number',
    'documentNumber',
    'cashBook_invoice_number',
    'belegnummer',
  ]);
}

/** @param {Record<string, unknown>} row */
function invoiceIdFrom(row) {
  return pickFirstString(row, [
    'invoice_id',
    'invoiceId',
    'invoice_uid',
    'uid',
    'cashBook_id',
    'id',
  ]);
}

/** @param {Record<string, unknown>} row */
function invoicePaymentFrom(row) {
  return pickFirstString(row, [
    'invoice_payment',
    'invoicePayment',
    'payment',
    'payment_type',
    'paymentType',
    'payment_method',
    'paymentMethod',
    'invoice_mode',
    'invoiceMode',
    'mode',
  ]);
}

/** @param {Record<string, unknown>} row */
function invoiceTimestampFrom(row) {
  return pickFirstString(row, [
    'invoice_timestamp',
    'invoiceTimestamp',
    'timestamp',
    'date',
    'created_at',
    'createdAt',
    'cashBook_timestamp',
  ]);
}

/** @param {Record<string, unknown>} row */
function invoiceDescriptionFrom(row) {
  return pickFirstString(row, [
    'invoice_description',
    'invoiceDescription',
    'description',
    'text',
    'cashBook_description',
  ]);
}

/** Stable fingerprint for synthetic ref (sorted keys). */
function rowFingerprint(row) {
  const keys = Object.keys(row).sort();
  const parts = keys.map((k) => `${k}=${JSON.stringify(row[k])}`);
  return parts.join('|').slice(0, 4000);
}

/** Odoo `ref` / idempotency: printable, non-empty, bounded length. */
function sanitizeOdooRef(s) {
  let t = String(s ?? '')
    .trim()
    .replace(/[\x00-\x1f\x7f]/g, '')
    .slice(0, 200);
  if (!t) t = 'HC';
  return t;
}

/**
 * Prefer invoice / document number, then id. If API omits both, use deterministic HC-<hex> from row + amount.
 * @param {Record<string, unknown>} row
 * @param {number} amount
 */
function invoiceRef(row, amount) {
  const num = invoiceNumberFrom(row);
  if (num && num !== '0') return sanitizeOdooRef(num);
  const idStr = invoiceIdFrom(row);
  if (idStr) return sanitizeOdooRef(idStr);
  let h = 5381;
  const basis = `${rowFingerprint(row)}|${Number.isFinite(amount) ? amount.toFixed(6) : 'na'}`;
  for (let i = 0; i < basis.length; i++) h = ((h << 5) + h + basis.charCodeAt(i)) >>> 0;
  return sanitizeOdooRef(`HC-${(h >>> 0).toString(16).padStart(8, '0')}`);
}

if (entries.length === 0) {
  console.warn(`${NODE}: HelloCash returned empty entries`, {
    rawType: typeof hc,
    rawKeys: hc && typeof hc === 'object' ? Object.keys(hc) : [],
    fetchedAt: hc.meta?.fetchedAt ?? input.fetchedAt ?? 'unknown',
  });
  return [
    {
      json: {
        skipped: false,
        mappedEmpty: true,
        message: 'No rows to map from HelloCash payload',
      },
    },
  ];
}

console.log(`${NODE}: HelloCash payload received`, {
  entryCount: entries.length,
  firstEntry: entries[0] ?? null,
  fetchedAt: hc.meta?.fetchedAt ?? input.fetchedAt ?? 'unknown',
});

const out = [];
const ac = /** @type {Record<string, number>} */ (config.accounts || {});
const odoo = /** @type {Record<string, unknown>} */ (config.odoo || {});

/** @type {Record<string, unknown>} */
const invByNum =
  hc.invoices && typeof hc.invoices === 'object' && !Array.isArray(hc.invoices)
    ? /** @type {Record<string, unknown>} */ (hc.invoices)
    : {};

const emptyTax = [];

let skippedCancelled = 0;
let skippedAmount = 0;

for (const inv of entries) {
  if (!inv || typeof inv !== 'object') continue;
  if (isInvoiceCancelled(inv)) {
    skippedCancelled++;
    continue;
  }

  const row = /** @type {Record<string, unknown>} */ (inv);
  const idStr = invoiceIdFrom(row);
  const numStr = invoiceNumberFrom(row);
  const linked =
    numStr && invByNum[numStr] && typeof invByNum[numStr] === 'object'
      ? /** @type {Record<string, unknown>} */ (invByNum[numStr])
      : null;
  if (linked && isInvoiceCancelled(linked)) {
    skippedCancelled++;
    continue;
  }

  const amount = parseInvoiceGross(row);
  if (!Number.isFinite(amount) || amount === 0) {
    skippedAmount++;
    continue;
  }

  const paymentRow = linked ? Object.assign({}, row, linked) : row;
  const paymentRaw = invoicePaymentFrom(paymentRow);
  let route = normalizeInvoicePayment(paymentRaw);
  if (!route) {
    console.warn(
      `${NODE}: unknown invoice_payment ${JSON.stringify(paymentRaw)} for invoice ${numStr || idStr || '(no id)'}; falling back to Bar routing`,
    );
    route = 'BAR';
  }

  const tsRaw = invoiceTimestampFrom(linked ? paymentRow : row);
  const date = tsRaw.split(' ')[0] || new Date().toISOString().split('T')[0];
  const ref = invoiceRef(row, amount);
  const desc = invoiceDescriptionFrom(linked ? paymentRow : row);
  const lineNameBase = `HC ${numStr || idStr || '—'}: ${desc.substring(0, 50)}`;

  const taxSource =
    linked && Array.isArray(linked.taxes) && linked.taxes.length > 0 ? linked : row;

  let taxRate = 19;
  if (Array.isArray(taxSource.taxes) && taxSource.taxes.length > 0) {
    const tax = taxSource.taxes[0];
    if (tax && typeof tax === 'object' && /** @type {{ tax_taxRate?: unknown }} */ (tax).tax_taxRate !== undefined) {
      taxRate = parseInt(String(/** @type {{ tax_taxRate?: unknown }} */ (tax).tax_taxRate), 10) || 19;
    }
  }

  let net = parseInvoiceNet(taxSource);
  let vat = parseInvoiceVat(taxSource);
  if (
    linked &&
    Array.isArray(taxSource.taxes) &&
    taxSource.taxes.length > 0 &&
    Number.isFinite(net) &&
    Number.isFinite(vat)
  ) {
    const sum = net + vat;
    if (Number.isFinite(amount) && sum > 0 && Math.abs(amount - sum) > 0.02) {
      const scale = amount / sum;
      net *= scale;
      vat *= scale;
    }
  }
  const hasTaxBreakdown = Number.isFinite(net) && net > 0 && Number.isFinite(vat) && vat >= 0;

  if (hasTaxBreakdown && Math.abs(net + vat - amount) > 0.02) {
    console.warn(`${NODE}: gross/net/VAT mismatch > 0.02 for ref ${ref}`, {
      gross: amount,
      net,
      vat,
      sum: net + vat,
    });
  }

  /** @type {number} */
  let journalId = 0;
  /** @type {number | undefined} */
  let debitAccount;
  const creditAccount = ac.erloese;
  /** @type {Record<string, unknown> | null} */
  let odooExtras = null;

  if (route === 'BAR') {
    journalId = resolveJournal(odoo.journalKasse, odoo, 'JOURNAL_KASSE');
    debitAccount = ac.kasse;
  } else if (route === 'BANKOMAT') {
    journalId = resolveJournal(odoo.journalBank, odoo, 'JOURNAL_BANK');
    debitAccount = ac.ec;
  } else if (route === 'KREDITKARTE') {
    journalId = resolveJournal(odoo.journalBank, odoo, 'JOURNAL_BANK');
    debitAccount = ac.kreditkarte;
  } else {
    journalId = resolveJournal(odoo.journalVerkauf, odoo, 'JOURNAL_VERKAUF');
    debitAccount = ac.rechnung;
    odooExtras = { payment_state: 'not_paid' };
  }

  const taxAccount = taxRate === 7 ? ac.ust7 : ac.ust19;

  /** @type {any[]} */
  let lineIds;
  if (hasTaxBreakdown) {
    lineIds = [
      [0, 0, { account_id: debitAccount, debit: amount, credit: 0, name: lineNameBase, tax_ids: emptyTax }],
      [0, 0, { account_id: creditAccount, debit: 0, credit: net, name: lineNameBase, tax_ids: emptyTax }],
      [
        0,
        0,
        {
          account_id: taxAccount,
          debit: 0,
          credit: vat,
          name: `${lineNameBase} (USt ${taxRate}%)`,
          tax_ids: emptyTax,
        },
      ],
    ];
  } else {
    lineIds = [
      [0, 0, { account_id: debitAccount, debit: amount, credit: 0, name: lineNameBase, tax_ids: emptyTax }],
      [0, 0, { account_id: creditAccount, debit: 0, credit: amount, name: lineNameBase, tax_ids: emptyTax }],
    ];
  }

  /** @type {Record<string, unknown>} */
  const odooVals = {
    ref,
    move_type: 'entry',
    journal_id: journalId,
    date,
    line_ids: lineIds,
    narration:
      `[n8n:hellocash→odoo] HelloCash Invoice #${numStr || '—'} (ID:${idStr || '—'}), invoice_payment:${paymentRaw || 'n/a'}, Amt:${amount.toFixed(2)}`,
  };
  if (odooExtras) Object.assign(odooVals, odooExtras);

  console.log(`${NODE}: mapped invoice ${idStr || ref}`, {
    ref,
    paymentMethod: route,
    amount,
    taxRate,
    hasTaxBreakdown,
    net: hasTaxBreakdown ? net : undefined,
    vat: hasTaxBreakdown ? vat : undefined,
  });

  out.push({
    json: {
      hellocashId: idStr || ref,
      hellocashNumber: numStr || null,
      invoiceNumber: numStr || null,
      paymentMethod: route,
      taxRate,
      ref,
      odooVals,
    },
  });
}

if (out.length === 0) {
  const first = entries[0] && typeof entries[0] === 'object' ? /** @type {object} */ (entries[0]) : null;
  const firstKeys = first ? Object.keys(first).slice(0, 50) : [];
  console.warn(`${NODE}: nothing mapped`, {
    entryCount: entries.length,
    skippedCancelled,
    skippedAmount,
    firstEntryKeys: firstKeys,
  });
  return [
    {
      json: {
        skipped: false,
        mappedEmpty: true,
        message:
          'No entries mapped (cancellation, zero/unparseable gross amount, or missing totals). Check invoice_total / taxes[].tax_gross and invoice_cancellation.',
        diagnostic: {
          entryCount: entries.length,
          skippedCancelled,
          skippedAmount,
          firstEntryKeys: firstKeys,
        },
      },
    },
  ];
}

return out;

/*
TEST FIXTURE — 119.00 € gross, 19 % USt (manual 3-line split, no Odoo auto-tax):

const row = {
  invoice_number: 'TEST-119',
  invoice_payment: 'Bar',
  invoice_total: '119.00',
  invoice_cancellation: '0',
  invoice_timestamp: '2026-05-13 12:00:00',
  taxes: [{ tax_taxRate: '19', tax_gross: '119.00', tax_net: '100.00', tax_tax: '19.00' }],
};
// With amount=gross=119, net=100, vat=19, hasTaxBreakdown=true, debitAccount=1612, creditAccount=1912, taxAccount=ust19:
// line_ids = [
//   [0, 0, { account_id: 1612, debit: 119, credit: 0, name: 'HC TEST-119: …', tax_ids: [] }],
//   [0, 0, { account_id: 1912, debit: 0, credit: 100, name: 'HC TEST-119: …', tax_ids: [] }],
//   [0, 0, { account_id: <ACCOUNT_UST_19>, debit: 0, credit: 19, name: 'HC TEST-119: … (USt 19%)', tax_ids: [] }],
// ];
*/

/**
* Odoo JSON-RPC: account.move create with idempotency (ref) and retries.
* Uses $env.ODOO_API_KEY (validated at Config Loader, never stored in config json).
*
* KORREKTUREN:
* 1. Hauptlogik als async Arrow-Funktion `run`, damit `this` vom Code-Node-Sandbox erhalten bleibt.
* 2. JSON-RPC über this.helpers.httpRequest (Code-Node v2; $http ist hier nicht verfügbar).
* 3. httpRequest mit json:true liefert das geparste JSON-RPC-Objekt direkt (kein response.data).
* 4. Fehler: response.status / statusCode (axios-ähnlich), Transport-Diagnostik bei leerem Body.
* 5. Rückgabe des Promise von run() an n8n.
*/

const NODE = 'Odoo Post Moves';

function safeStringify(v) {
try {
return JSON.stringify(v, null, 2);
} catch {
return '[unserializable]';
}
}

function isDebugEnabled() {
const v = String($env.ODOO_DEBUG_LOG ?? '').trim().toLowerCase();
return v === '1' || v === 'true' || v === 'yes';
}

/** Max chars for error response/debug snippets in messages and logs (avoid single-line truncation in Docker). */
function errorSnippetLimit() {
const raw = String($env.ODOO_ERROR_SNIPPET_CHARS ?? '').trim();
const n = parseInt(raw, 10);
if (Number.isFinite(n) && n > 0) return Math.min(n, 200000);
return 8000;
}

/**
* Split a long string into log-sized chunks so each docker/n8n log line stays complete.
* @param {string} text
* @param {number} chunkSize
* @returns {string[]}
*/
function chunkForLogs(text, chunkSize = 3500) {
const s = String(text ?? '');
if (!s) return ['(empty)'];
const out = [];
for (let i = 0; i < s.length; i += chunkSize) {
out.push(s.slice(i, i + chunkSize));
}
return out;
}

/**
* Walk Error.cause (and plain { cause }) chains for fuller diagnostics.
* @param {unknown} e
* @returns {unknown[]}
*/
function walkCauses(e) {
const list = [];
let cur = e;
for (let depth = 0; depth < 10 && cur != null; depth++) {
list.push(cur);
if (cur instanceof Error && cur.cause !== undefined) {
cur = cur.cause;
} else if (typeof cur === 'object' && cur !== null && 'cause' in cur) {
cur = /** @type {{ cause?: unknown }} */ (cur).cause;
} else {
break;
}
}
return list;
}

/**
* Verbose multi-line stderr — avoids one huge line that gets truncated as `error | Cannot ` in docker.
* @param {string} context
* @param {unknown} e
* @param {Record<string, unknown>} [extra]
*/
function logErrorVerbose(context, e, extra = {}) {
const lim = errorSnippetLimit();
console.error(`${NODE}: ERROR [${context}]`);
try {
console.error(`${NODE}: ERROR [${context}] extra`, extra);
} catch {
// ignore
}
let idx = 0;
for (const cur of walkCauses(e)) {
const tag = idx === 0 ? 'root' : `cause[${idx}]`;
idx++;
if (cur instanceof Error) {
console.error(`${NODE}: ERROR [${context}] ${tag} name=${cur.name} message=${cur.message}`);
if (cur.stack) {
for (const line of chunkForLogs(cur.stack, 3500)) {
console.error(`${NODE}: ERROR [${context}] ${tag} stack`, line);
}
}
} else {
console.error(`${NODE}: ERROR [${context}] ${tag} (non-Error)`, safeStringify(cur).slice(0, lim));
}
}
const any = /** @type {{ response?: { statusCode?: unknown, status?: unknown, body?: unknown, data?: unknown } }} */ (e);
const st = any?.response?.statusCode ?? any?.response?.status;
const bod =
any?.response?.data ?? any?.response?.body ?? /** @type {{ body?: unknown }} */ (e)?.body;
if (st !== undefined || bod !== undefined) {
const bodyStr =
typeof bod === 'string' ? bod : bod !== undefined && bod !== null ? safeStringify(bod) : '';
console.error(`${NODE}: ERROR [${context}] httpSummary`, {
httpStatus: st,
bodySnippetChars: Math.min(bodyStr.length, lim),
});
const parts = chunkForLogs(bodyStr.slice(0, lim), 3500);
parts.forEach((part, c) => {
console.error(`${NODE}: ERROR [${context}] body part ${c + 1}/${parts.length}`, part);
});
}
}

function debugLog(label, obj) {
try {
console.debug(`${NODE}: ${label}`, obj);
} catch {
// ignore
}
}

/**
* Redact the password in an execute_kw JSON-RPC body.
* Body shape:
* params.args = [db, uid, password, model, method, args, kwargs]
*/
function redactRpcBody(body) {
try {
const b = body && typeof body === 'object' ? { ...body } : body;
if (!b || typeof b !== 'object') return b;
const params = b.params && typeof b.params === 'object' ? { ...b.params } : null;
if (!params) return b;
const pArgs = Array.isArray(params.args) ? [...params.args] : null;
if (!pArgs) return b;
if (pArgs.length >= 3) pArgs[2] = '***REDACTED***';
b.params = { ...params, args: pArgs };
return b;
} catch {
return { redaction: 'failed' };
}
}

/**
* Best-effort HTTP status aus httpRequest/axios-ähnlichen Fehlern.
* @param {unknown} e
*/
function resolveHttpStatus(e) {
/** @param {unknown} x */
const asStatus = (x) => {
if (x === undefined || x === null || x === '') return undefined;
if (typeof x === 'number' && Number.isFinite(x)) return x;
const n = parseInt(String(x), 10);
if (Number.isFinite(n)) return n;
if (typeof x === 'string') return x.trim() || undefined;
return undefined;
};

let cur = e;
for (let d = 0; d < 6 && cur != null; d++) {
if (typeof cur !== 'object') break;
const o = /** @type {Record<string, unknown>} */ (cur);
const u =
asStatus(o.response?.status) ??
asStatus(o.response?.statusCode) ??
asStatus(
o.error && typeof o.error === 'object'
? /** @type {{ status?: unknown, statusCode?: unknown }} */ (o.error).status ??
/** @type {{ status?: unknown, statusCode?: unknown }} */ (o.error).statusCode ??
undefined
: undefined,
) ??
asStatus(o.httpCode) ??
asStatus(o.statusCode) ??
asStatus(o.status);
if (u !== undefined) return u;
cur = o.cause;
}

const msg = String(
(typeof e === 'object' && e && 'message' in e && /** @type {{ message: unknown }} */ (e).message) || '',
);
const m =
msg.match(/\bstatus code\s+(\d{3})\b/i) ??
msg.match(/\bHTTP\s+(\d{3})\b/) ??
msg.match(/^\s*(\d{3})\s/);
if (m) return parseInt(m[1], 10);

return 'no-status';
}

/**
* Best-effort HTTP error payload text (Odoo often returns JSON in body on 4xx/5xx).
* @param {unknown} e
* @returns {string | undefined} undefined if nothing readable (network/TLS/DNS errors often have no body)
*/
function extractHttpErrorPayload(e) {
let body =
/** @type {{ response?: { data?: unknown, body?: unknown } }} */ (e)?.response?.data ??
/** @type {{ response?: { data?: unknown, body?: unknown } }} */ (e)?.response?.body ??
/** @type {{ body?: unknown }} */ (e)?.body ??
null;
if ((body === undefined || body === null || body === '') && e && typeof e === 'object' && 'cause' in e) {
let cur = /** @type {{ cause?: unknown }} */ (e).cause;
for (let d = 0; d < 6 && cur != null; d++) {
if (typeof cur === 'object' && cur !== null) {
const c = /** @type {{ response?: { data?: unknown, body?: unknown } } } */ (cur);
body = c.response?.data ?? c.response?.body ?? null;
if (body !== undefined && body !== null && body !== '') break;
cur = 'cause' in cur ? /** @type {{ cause?: unknown }} */ (cur).cause : null;
} else break;
}
}
if (body === undefined || body === null || body === '') return undefined;
return typeof body === 'string' ? body : JSON.stringify(body, null, 2);
}

/**
* Syserror fields when there is no HTTP body (ECONNREFUSED, ENOTFOUND, cert, etc.).
* @param {unknown} e
*/
function transportDiagnostics(e) {
const parts = [];
const seen = new Set();
const add = (p) => {
if (!p || seen.has(p)) return;
seen.add(p);
parts.push(p);
};
const visit = (o) => {
if (!o || typeof o !== 'object') return;
const x = /** @type {Record<string, unknown>} */ (o);
if (typeof x.code === 'string' && x.code) add(`code=${x.code}`);
if (x.errno != null && x.errno !== '') add(`errno=${x.errno}`);
if (typeof x.syscall === 'string' && x.syscall) add(`syscall=${x.syscall}`);
if (typeof x.hostname === 'string' && x.hostname) add(`host=${x.hostname}`);
if (x.address != null && x.address !== '') add(`address=${String(x.address)}`);
if (x.port != null && x.port !== '') add(`port=${String(x.port)}`);
};
for (const cur of walkCauses(e)) visit(cur);
return parts.join(' ');
}

function nowIso() {
return new Date().toISOString();
}

/** Mask secret for logs. */
function maskSecret(s) {
const str = String(s ?? '');
if (!str) return '(empty)';
if (str.length <= 8) return `${str.slice(0, 2)}…(${str.length} chars)`;
return `${str.slice(0, 3)}…${str.slice(-2)} (len=${str.length})`;
}

/**
* Exponential backoff with jitter.
* @param {number} attempt 1..n
* @param {number} baseMs
* @param {number} maxMs
*/
function backoffDelayMs(attempt, baseMs, maxMs) {
const exp = Math.min(maxMs, baseMs * Math.pow(2, Math.max(0, attempt - 1)));
const jitter = Math.floor(Math.random() * Math.min(250, exp * 0.1));
return exp + jitter;
}

function createCircuitBreaker({ failureThreshold, cooldownMs }) {
let consecutive = 0;
let openUntil = 0;
return {
assertClosed(op) {
const now = Date.now();
if (openUntil && now < openUntil) {
const remainingMs = openUntil - now;
throw new Error(
`${NODE}: circuit breaker OPEN for ${op} (cooldown ${Math.ceil(remainingMs / 1000)}s remaining). ` +
`Too many consecutive failures; check Odoo availability/config before retrying.`,
);
}
},
success() {
consecutive = 0;
openUntil = 0;
},
failure() {
consecutive++;
if (consecutive >= failureThreshold) openUntil = Date.now() + cooldownMs;
},
};
}

/**
* Validate a move payload so we fail fast before sending bad accounting data.
* @param {any} vals
*/
function validateMoveVals(vals) {
if (!vals || typeof vals !== 'object') return 'odooVals must be an object';
if (!vals.ref || typeof vals.ref !== 'string') return 'odooVals.ref missing (string required)';
if (!vals.journal_id || !Number.isFinite(parseInt(String(vals.journal_id), 10)))
return 'odooVals.journal_id missing/invalid';
if (!vals.date || !/^\d{4}-\d{2}-\d{2}$/.test(String(vals.date))) return 'odooVals.date must be YYYY-MM-DD';
if (!Array.isArray(vals.line_ids) || vals.line_ids.length < 2) return 'odooVals.line_ids must have >= 2 lines';

let debitSum = 0;
let creditSum = 0;
for (const li of vals.line_ids) {
if (!Array.isArray(li) || li.length < 3) return 'odooVals.line_ids must contain [0,0,line] entries';
const line = li[2];
if (!line || typeof line !== 'object') return 'odooVals.line_ids line payload must be object';
const acct = line.account_id;
if (!acct || !Number.isFinite(parseInt(String(acct), 10))) return 'line.account_id missing/invalid';
const d = parseFloat(String(line.debit ?? '0'));
const c = parseFloat(String(line.credit ?? '0'));
if (!Number.isFinite(d) || d < 0) return 'line.debit must be a non-negative number';
if (!Number.isFinite(c) || c < 0) return 'line.credit must be a non-negative number';
debitSum += d;
creditSum += c;
}
// Allow tiny rounding differences.
if (Math.abs(debitSum - creditSum) > 0.0001) {
return `move not balanced: debit=${debitSum.toFixed(2)} credit=${creditSum.toFixed(2)}`;
}
return null;
}

/**
 * Classify Odoo RPC error text for batch handling (permanent business conflict vs retryable).
 * @param {string} errorMessage
 * @returns {{ permanent: boolean, reason: string, action: string }}
 */
function classifyOdooError(errorMessage) {
  const msg = String(errorMessage ?? '');
  const rows = [
    { re: /another model is using/i, reason: 'odoo_move_locked', action: 'skip_and_alert' },
    { re: /record you are trying to delete/i, reason: 'odoo_move_locked', action: 'skip_and_alert' },
    { re: /already reconciled/i, reason: 'odoo_move_reconciled', action: 'skip_and_alert' },
    { re: /cannot delete posted/i, reason: 'odoo_move_posted', action: 'skip_and_alert' },
  ];
  for (const row of rows) {
    if (row.re.test(msg)) {
      return { permanent: true, reason: row.reason, action: row.action };
    }
  }
  return { permanent: false, reason: 'retryable', action: 'retry' };
}

/** @param {unknown} j */
function isPermanentOdooSkip(j) {
  return (
    j &&
    typeof j === 'object' &&
    /** @type {{ skipped?: unknown, reason?: unknown }} */ (j).skipped === true &&
    typeof /** @type {{ reason?: unknown }} */ (j).reason === 'string' &&
    String(/** @type {{ reason?: string }} */ (j).reason).startsWith('odoo_')
  );
}

/**
* Hauptfunktion – Arrow, damit this.helpers beim Aufruf `return run()` gesetzt bleibt.
* @returns {Promise<any[]>} Ergebnisse für n8n
*/
const run = async () => {
const config = $('Config Loader').first().json;
const apiKey = $env.ODOO_API_KEY?.trim();
if (!apiKey) {
throw new Error(
`${NODE}: ODOO_API_KEY missing for JSON-RPC. Example: ODOO_API_KEY="supersecret" (never log this value).`,
);
}

const { maxAttempts, intervalMs } = config.retry;
const results = [];
const debug = isDebugEnabled();

// Startup diagnostics (no secrets).
console.log(`${NODE}: start`, {
at: nowIso(),
odooBaseUrl: config?.odoo?.baseUrl,
odooDb: config?.odoo?.db,
odooUid: config?.odoo?.uid,
journalId: config?.odoo?.journalId,
apiKey: maskSecret(apiKey),
maxAttempts,
intervalMs,
debug,
});

const breaker = createCircuitBreaker({
failureThreshold: parseInt(String($env.ODOO_CB_FAILURE_THRESHOLD || '4'), 10) || 4,
cooldownMs: parseInt(String($env.ODOO_CB_COOLDOWN_MS || '120000'), 10) || 120000,
});

/**
* JSON-RPC Aufruf mit this.helpers.httpRequest.
* @param {string} model
* @param {string} method
* @param {any[]} args
* @param {Record<string, any>} kwargs
* @param {number} rpcAttempt 1..maxAttempts (verbose logs only on final attempt)
*/
const rpc = async (model, method, args, kwargs = {}, rpcAttempt = 1) => {
const url = `${config.odoo.baseUrl}/jsonrpc`;
const body = {
jsonrpc: '2.0',
method: 'call',
params: {
service: 'object',
method: 'execute_kw',
args: [
config.odoo.db,
config.odoo.uid,
String(apiKey).trim(),
model,
method,
args,
kwargs,
],
},
id: Date.now(),
};

if (debug) {
console.log(`${NODE}: RPC request (redacted)`, {
at: nowIso(),
url,
model,
method,
body: redactRpcBody(body),
});
}

let res;
try {
breaker.assertClosed(`${model}.${method}`);
res = await this.helpers.httpRequest({
method: 'POST',
url,
body,
json: true,
timeout: 60000,
headers: { 'Content-Type': 'application/json' },
});
breaker.success();
} catch (e) {
breaker.failure();
// axios-ähnlich: response.status; manche Versionen: statusCode
const status =
e.response?.status ?? e.response?.statusCode ?? e.statusCode ?? resolveHttpStatus(e);
const errMsg = e.message || String(e);
const lim = errorSnippetLimit();
const directBody = e.response?.data ?? e.response?.body ?? e.body;
const payloadText =
directBody !== undefined && directBody !== null && directBody !== ''
? typeof directBody === 'string'
? directBody
: JSON.stringify(directBody, null, 2)
: extractHttpErrorPayload(e);
const transport = transportDiagnostics(e);
const responseSummary =
payloadText !== undefined
? String(payloadText).slice(0, lim)
: transport
? `(no HTTP response body; ${transport})`
: `(no HTTP response body — typical for ECONNREFUSED/ENOTFOUND/ETIMEDOUT/TLS/DNS; primary error: ${errMsg})`;
if (rpcAttempt === maxAttempts) {
logErrorVerbose(`rpc HTTP ${model}.${method}`, e, {
url,
model,
method,
httpStatus: status,
message: errMsg,
transport,
payloadSnippet: payloadText ? String(payloadText).slice(0, 2000) : undefined,
apiKey: maskSecret(apiKey),
requestBodyRedacted: redactRpcBody(body),
});
} else {
console.error(`${NODE}: Odoo HTTP error (will retry ${rpcAttempt}/${maxAttempts})`, {
url,
model,
method,
httpStatus: status,
message: errMsg,
transport,
requestBodyRedacted: redactRpcBody(body),
});
}
const statusLine =
status && status !== 'no-status'
? `HTTP ${status}`
: `HTTP status unknown — check ODOO_BASE_URL, TLS, proxy, and that Odoo is reachable`;
throw new Error(
`${errMsg} | ${statusLine} | ${model}.${method} | ${responseSummary}`,
);
}

if (res.error) {
const dbg = String(res.error.data?.debug ?? res.error.message ?? 'none');
const msg = String(res.error.data?.message ?? res.error.message ?? '');
const lim = errorSnippetLimit();
if (rpcAttempt === maxAttempts) {
console.error(`${NODE}: Odoo RPC error`, {
model,
method,
code: res.error.code,
message: msg,
});
for (const part of chunkForLogs(dbg, 3500)) {
console.error(`${NODE}: Odoo RPC error debug chunk`, part);
}
} else {
console.error(`${NODE}: Odoo RPC error (retry ${rpcAttempt}/${maxAttempts})`, {
model,
method,
code: res.error.code,
message: msg,
});
}
throw new Error(
`Odoo RPC | ${model}.${method} | code=${res.error.code} | ${msg} | debug:${dbg.slice(0, lim)}`,
);
}

console.log(`${NODE}: Odoo RPC ok: ${model}.${method}`, {
resultType: Array.isArray(res.result) ? 'array' : typeof res.result,
resultLength: Array.isArray(res.result) ? res.result.length : undefined,
});

return res.result;
};

/**
* RPC with retries/backoff.
* @param {string} model
* @param {string} method
* @param {any[]} args
* @param {Record<string, any>} kwargs
* @param {string} op
*/
const rpcWithRetry = async (model, method, args, kwargs, op) => {
let last = null;
for (let attempt = 1; attempt <= maxAttempts; attempt++) {
try {
return { ok: true, result: await rpc(model, method, args, kwargs, attempt), attempt };
} catch (e) {
last = e;
const msg = e instanceof Error ? e.message : String(e);
console.warn(`${NODE}: ${op} failed (attempt ${attempt}/${maxAttempts}): ${msg}`);
if (attempt < maxAttempts) {
const delay = backoffDelayMs(attempt, intervalMs, 30000);
// Mehrere Werte in einem Objekt
debugLog('Zwischenstand', { ref: kwargs?.ref ?? undefined, attempt, delayMs: delay });
await new Promise((r) => setTimeout(r, delay));
}
}
}
return { ok: false, error: last };
};

// Hauptschleife über alle eingehenden Items
for (const item of items) {
const j = item.json;

if (j.skipped || j.empty || j.mappedEmpty) {
results.push({ json: { ...j, odooSkipped: true, reason: 'no_data' } });
continue;
}

if (!j.odooVals?.ref) {
results.push({ json: { ...j, error: 'Missing odooVals.ref' } });
continue;
}

const { hellocashId, hellocashNumber, invoiceNumber, ref, odooVals, paymentMethod, taxRate } = j;

console.log(`${NODE}: processing item ${ref}`, { hellocashId, ref, at: nowIso() });

const validationError = validateMoveVals(odooVals);
if (validationError) {
results.push({
json: {
...j,
success: false,
error: `Invalid journal entry payload: ${validationError}`,
odooSkipped: true,
reason: 'invalid_payload',
},
});
continue;
}

// Log what we are about to send (safe summary by default).
const lineCount = Array.isArray(odooVals?.line_ids) ? odooVals.line_ids.length : 0;
let debitSum = 0;
let creditSum = 0;
try {
if (Array.isArray(odooVals?.line_ids)) {
for (const li of odooVals.line_ids) {
const line = Array.isArray(li) ? li[2] : null;
if (!line || typeof line !== 'object') continue;
const d = parseFloat(String(line.debit ?? '0'));
const c = parseFloat(String(line.credit ?? '0'));
if (Number.isFinite(d)) debitSum += d;
if (Number.isFinite(c)) creditSum += c;
}
}
} catch {}

console.log(`${NODE}: odoo payload summary`, {
at: nowIso(),
ref,
date: odooVals?.date,
journal_id: odooVals?.journal_id,
lineCount,
debitSum: Number.isFinite(debitSum) ? Number(debitSum.toFixed(2)) : null,
creditSum: Number.isFinite(creditSum) ? Number(creditSum.toFixed(2)) : null,
});

if (debug) {
console.log(`${NODE}: odoo payload FULL (create)`, {
at: nowIso(),
ref,
odooVals,
});
// Ausgabe von Variablen als lesbares JSON
console.log(`${NODE}: Debug odooVals`, JSON.stringify(odooVals, null, 2));
}

// Idempotency check
const dedupe = await rpcWithRetry(
'account.move',
'search_read',
[[['ref', '=', ref]]],
{ fields: ['id', 'state', 'name', 'ref'], limit: 1 },
`idempotency check ref=${ref}`,
);
if (!dedupe.ok) {
const msg = dedupe.error instanceof Error ? dedupe.error.message : String(dedupe.error);
results.push({
json: {
...j,
success: false,
error:
`Idempotency check failed — move not created to avoid duplicates. ` +
`Fix Odoo connectivity and re-run. Details: ${msg}`,
odooSkipped: true,
reason: 'dedupe_check_failed',
},
});
continue;
}
const existing = dedupe.result;
if (Array.isArray(existing) && existing.length > 0) {
console.log(`${NODE}: skipping duplicate: ${ref}`, { odooMoveId: existing[0].id });
results.push({
json: {
hellocashId,
hellocashNumber,
invoiceNumber,
ref,
odooMoveId: existing[0].id,
odooState: existing[0].state,
success: true,
idempotent: true,
message: `Already exists as ${existing[0].name || ref}`,
},
});
continue;
}

const createRes = await rpcWithRetry('account.move', 'create', [[odooVals]], {}, `create ref=${ref}`);
if (!createRes.ok) {
const msg = createRes.error instanceof Error ? createRes.error.message : String(createRes.error);
const classification = classifyOdooError(msg);

if (classification.permanent) {
console.error(`${NODE}: permanent Odoo conflict — skip item`, {
ref,
hellocashId,
classification,
error: msg,
});
results.push({
json: {
...j,
success: false,
skipped: true,
reason: classification.reason,
error: msg,
odooMoveId: j.odooMoveId ?? null,
hellocashId,
ref,
action: 'requires_manual_reconciliation',
},
});
continue;
}

// Safety net: post‑failure check (retryable path only)
const postCheck = await rpcWithRetry(
'account.move',
'search_read',
[[['ref', '=', ref]]],
{ fields: ['id', 'state', 'name'], limit: 1 },
`post-failure dedupe check ref=${ref}`,
);
if (postCheck.ok && Array.isArray(postCheck.result) && postCheck.result.length > 0) {
results.push({
json: {
hellocashId,
hellocashNumber,
invoiceNumber,
ref,
odooMoveId: postCheck.result[0].id,
odooState: postCheck.result[0].state,
success: true,
idempotent: true,
message: `Move appears to have been created despite error; found as ${postCheck.result[0].name || ref}`,
},
});
continue;
}

results.push({
json: {
...j,
success: false,
error: `Failed to create move after ${maxAttempts} attempts: ${msg}`,
odooSkipped: false,
reason: 'create_failed',
},
});
continue;
}

const createdId = Array.isArray(createRes.result) ? createRes.result[0] : createRes.result;
console.log(`${NODE}: created Odoo move for ${ref}`, { odooMoveId: createdId });
results.push({
json: {
hellocashId,
hellocashNumber,
invoiceNumber,
ref,
odooMoveId: createdId,
paymentMethod,
taxRate,
success: true,
attempt: createRes.attempt,
createdAt: nowIso(),
},
});
}

// ── Post-loop failure gate ──────────────────────
const permanentSkips = results.filter((r) => r.json && isPermanentOdooSkip(r.json));
if (permanentSkips.length > 0) {
console.warn(`${NODE}: permanent business conflicts summary (batch continues)`, {
at: nowIso(),
count: permanentSkips.length,
items: permanentSkips.map((r) => ({
ref: r.json?.ref,
hellocashId: r.json?.hellocashId,
reason: r.json?.reason,
})),
});
}

const hardFailures = results.filter(
(r) =>
r.json &&
!isPermanentOdooSkip(r.json) &&
(r.json.success === false ||
r.json.reason === 'dedupe_check_failed' ||
r.json.reason === 'invalid_payload'),
);

if (hardFailures.length > 0) {
const summary = hardFailures.map((r) => ({
ref: r.json.ref ?? 'unknown',
reason: r.json.reason ?? 'create_failed',
error: r.json.error ?? 'unknown error',
}));
console.error(`${NODE}: batch failure summary`, {
at: nowIso(),
failureCount: hardFailures.length,
totalItems: results.length,
odooBaseUrl: config?.odoo?.baseUrl,
journalId: config?.odoo?.journalId,
});
for (let i = 0; i < summary.length; i++) {
const f = summary[i];
console.error(
`${NODE}: failure ${i + 1}/${summary.length} ref=${f.ref} reason=${f.reason}`,
);
for (const part of chunkForLogs(String(f.error ?? ''), 3500)) {
console.error(`${NODE}: failure ${i + 1} detail`, part);
}
}
const first = summary[0];
throw new Error(
`${NODE}: ${hardFailures.length} item(s) failed (full details in logs above). First: ref=${first?.ref} reason=${first?.reason} — ${String(first?.error ?? '').slice(0, 500)}`,
);
}

return results;
};

// n8n Code node: return the Promise from run()
return run();
